#!/usr/bin/env node

/**
 * Upload all accessory product images to Supabase storage and upsert
 * their records (including the `variants` jsonb column) into `products`.
 *
 * Source: products.json accessory rows generated by build-accessories.js
 * from allaccs-data.js. Unlike upload-pails.js / upload-ladles.js (single
 * category, slice-based), this covers all 14 accessory categories in one
 * pass, selected by category name rather than array position.
 */

import { createClient } from "@supabase/supabase-js";
import fs from "fs";
import path from "path";
import { fileURLToPath } from "url";
import dotenv from "dotenv";

const __dirname = path.dirname(fileURLToPath(import.meta.url));

dotenv.config({ path: path.join(__dirname, "../../../../.env.local") });
dotenv.config({ path: path.join(__dirname, "../../../../.env") });

const SUPABASE_URL = process.env.REACT_APP_SUPABASE_URL || process.env.SUPABASE_URL;
const SERVICE_ROLE_KEY = process.env.SUPABASE_SERVICE_ROLE_KEY;

if (!SUPABASE_URL || !SERVICE_ROLE_KEY) {
  console.error("❌ Missing env vars: REACT_APP_SUPABASE_URL, SUPABASE_SERVICE_ROLE_KEY");
  process.exit(1);
}

const supabase = createClient(SUPABASE_URL, SERVICE_ROLE_KEY);

const IMAGES_DIR = path.join(__dirname, "../../../../../../../", "saworepo2", "images");
const PRODUCTS_JSON = path.join(__dirname, "../data/products.json");

const BUCKET = "product-images";
const STORAGE_PATH_PREFIX = "products/2026/07";

const ACCESSORY_CATEGORIES = new Set([
  "Pails", "Ladles", "Pail Shower", "Thermometers", "Clocks & Timers",
  "Sauna Lights", "Headrest & Backrest", "Doors & Handles", "Benches",
  "Cloth Hangers", "Wooden Floor Mats", "Kivistone",
  "Ventilation & Miscellaneous", "Accessory Sets",
]);

async function uploadImage(filename, cache) {
  if (cache[filename] !== undefined) return cache[filename];

  const localPath = path.join(IMAGES_DIR, filename);
  if (!fs.existsSync(localPath)) {
    console.warn(`  ⚠ File not found: ${filename}`);
    return (cache[filename] = null);
  }

  const ext = path.extname(filename).toLowerCase();
  const contentType = ext === ".png" ? "image/png" : ext === ".jpg" || ext === ".jpeg" ? "image/jpeg" : "image/webp";
  const storagePath = `${STORAGE_PATH_PREFIX}/${filename}`;
  const buffer = fs.readFileSync(localPath);

  try {
    const { error } = await supabase.storage.from(BUCKET).upload(storagePath, buffer, {
      contentType, upsert: true,
    });
    if (error) {
      console.warn(`  ⚠ Upload error for ${filename}: ${error.message}`);
      return (cache[filename] = null);
    }
    const { data } = supabase.storage.from(BUCKET).getPublicUrl(storagePath);
    return (cache[filename] = data.publicUrl);
  } catch (err) {
    console.warn(`  ⚠ Exception uploading ${filename}: ${err.message}`);
    return (cache[filename] = null);
  }
}

async function convertPath(localPath, cache) {
  if (!localPath) return null;
  if (localPath.includes("://")) return localPath;
  return uploadImage(path.basename(localPath), cache);
}

async function main() {
  console.log("🚀 Starting accessories upload to Supabase...\n");

  const raw = fs.readFileSync(PRODUCTS_JSON, "utf-8").replace(/^﻿/, "");
  const products = JSON.parse(raw);
  const accessories = products.filter(p => (p.categories || []).some(c => ACCESSORY_CATEGORIES.has(c)));

  console.log(`📦 Found ${accessories.length} accessory products across ${ACCESSORY_CATEGORIES.size} categories`);
  console.log("📤 Uploading images...\n");

  const cache = {};
  let done = 0;

  for (const product of accessories) {
    product.thumbnail = await convertPath(product.thumbnail, cache);

    if (Array.isArray(product.variants)) {
      product.variants = await Promise.all(
        product.variants.map(async v => ({ ...v, image: await convertPath(v.image, cache) }))
      );
    }
    if (Array.isArray(product.images)) {
      product.images = (await Promise.all(product.images.map(p => convertPath(p, cache)))).filter(Boolean);
    }
    if (Array.isArray(product.spec_images)) {
      product.spec_images = (await Promise.all(product.spec_images.map(p => convertPath(p, cache)))).filter(Boolean);
    }

    done++;
    if (done % 25 === 0) console.log(`  …processed ${done}/${accessories.length}`);
  }

  const uploadedCount = Object.values(cache).filter(Boolean).length;
  const failedCount = Object.values(cache).filter(v => v === null).length;
  console.log(`\n✅ Images processed. Uploaded/cached: ${uploadedCount}, failed: ${failedCount}\n`);

  console.log("📝 Deleting old accessory records and inserting updated ones...\n");

  const { error: deleteError } = await supabase
    .from("products")
    .delete()
    .overlaps("categories", [...ACCESSORY_CATEGORIES]);

  if (deleteError) {
    console.error("⚠️  Warning: Error deleting old accessory records:", deleteError.message);
  } else {
    console.log("  ✓ Deleted old accessory records");
  }

  const { data, error } = await supabase
    .from("products")
    .upsert(accessories, { onConflict: "slug" })
    .select("id, slug, name");

  if (error) {
    console.error("❌ Error upserting products:", error.message);
    process.exit(1);
  }

  console.log(`✅ Successfully upserted ${data?.length || 0} accessory products`);
  console.log("\n🎉 Upload complete! Flip dataSource to \"supabase\" (or wait for github sync) to verify.");
}

main().catch((err) => {
  console.error("❌ Fatal error:", err);
  process.exit(1);
});
